const LogisticsCenterTab: React.FC<LogisticsCenterTabProps> = ({ tasks, draftTasks, fetchSanons, onDeleteTask, hasPermission, resolveName }) => {
    const { t, language } = useLanguage();

    // --- FILTRE ---
    const todayStr = new Date().toISOString().split('T')[0];
    const [dateFrom, setDateFrom] = useState(todayStr);
    const [dateTo, setDateTo] = useState(todayStr);
    const [timeFrom, setTimeFrom] = useState('00:00');
    const [timeTo, setTimeTo] = useState('23:59');

    const [filterQuery, setFilterQuery] = useState('');
    const [quickFilter, setQuickFilter] = useState<'ALL' | 'INBOUND' | 'OUTBOUND' | 'PENDING'>('ALL');

    // --- DATA STATE ---
    const [historicalData, setHistoricalData] = useState<Task[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    // Načítanie historických dát ak je zvolený starší dátum
    useEffect(() => {
        const loadHistoryIfNeeded = async () => {
            if (dateFrom < todayStr || dateTo < todayStr) {
                setIsLoading(true);
                try {
                    const sanons = await fetchSanons();
                    const allArchived: Task[] = [];
                    sanons.forEach(s => {
                        if (s.tasks && Array.isArray(s.tasks)) {
                            allArchived.push(...s.tasks);
                        }
                    });
                    setHistoricalData(allArchived);
                } catch (e) {
                    console.error("Failed to load archive", e);
                } finally {
                    setIsLoading(false);
                }
            } else {
                setHistoricalData([]);
            }
        };
        loadHistoryIfNeeded();
    }, [dateFrom, dateTo, todayStr, fetchSanons]);

    // --- AGREGÁCIA A FILTRÁCIA ---
    const allLogisticsTasks = useMemo(() => {
        // Spojenie zdrojov
        const combined = [...tasks, ...draftTasks, ...historicalData];

        // Unifikácia podľa ID (prevencia duplikátov pri fetchovaní)
        const uniqueMap = new Map();
        combined.forEach(t => {
            if (t.isLogistics) uniqueMap.set(t.id, t);
        });

        const startTs = new Date(`${dateFrom}T${timeFrom}`).getTime();
        const endTs = new Date(`${dateTo}T${timeTo}`).getTime();

        return Array.from(uniqueMap.values())
            .filter((task: Task) => {
                const taskTime = task.completedAt || task.createdAt || 0;
                // Filter Dátum a Čas
                if (taskTime < startTs || taskTime > endTs) return false;

                // Quick Filter (Smer jazdy / Stav)
                if (quickFilter === 'INBOUND') {
                    const op = (task.workplace || '').toUpperCase();
                    if (!(op.includes('VYKLÁDKA') || op.includes('UNLOADING') || op.includes('PRÍJEM'))) return false;
                } else if (quickFilter === 'OUTBOUND') {
                    const op = (task.workplace || '').toUpperCase();
                    if (!(op.includes('NAKLÁDKA') || op.includes('LOADING') || op.includes('EXPEDÍCIA'))) return false;
                } else if (quickFilter === 'PENDING') {
                    if (task.isDone) return false;
                }

                // Fulltext vyhľadávanie
                if (filterQuery) {
                    const q = filterQuery.toLowerCase();
                    const searchable = `${task.partNumber} ${task.workplace} ${task.note} ${resolveName(task.completedBy)}`.toLowerCase();
                    if (!searchable.includes(q)) return false;
                }

                return true;
            })
            .sort((a, b) => (b.completedAt || b.createdAt || 0) - (a.completedAt || a.createdAt || 0));
    }, [tasks, draftTasks, historicalData, dateFrom, dateTo, timeFrom, timeTo, quickFilter, filterQuery, resolveName]);

    const stats = useMemo(() => {
        let inbound = 0;
        let outbound = 0;
        let pending = 0;

        allLogisticsTasks.forEach(task => {
            const qty = parseFloat((task.quantity || '0').replace(',', '.'));
            const op = (task.workplace || '').toUpperCase();

            if (op.includes('VYKLÁDKA') || op.includes('UNLOADING') || op.includes('PRÍJEM')) {
                inbound += qty;
            } else if (op.includes('NAKLÁDKA') || op.includes('LOADING') || op.includes('EXPEDÍCIA')) {
                outbound += qty;
            }

            if (!task.isDone) {
                pending++;
            }
        });

        return { inbound, outbound, pending };
    }, [allLogisticsTasks]);

    const formatTime = (ts?: number) => {
        if (!ts) return '-';
        const date = new Date(ts);
        const now = new Date();
        const isToday = date.toDateString() === now.toDateString();

        const yesterday = new Date(now);
        yesterday.setDate(yesterday.getDate() - 1);
        const isYesterday = date.toDateString() === yesterday.toDateString();

        const timeStr = date.toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });

        if (isToday) return language === 'sk' ? `Dnes, ${timeStr}` : `Today, ${timeStr}`;
        if (isYesterday) return language === 'sk' ? `Včera, ${timeStr}` : `Yesterday, ${timeStr}`;
        return date.toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit' }) + ' ' + timeStr;
    };

    const getQuantityString = (task: Task) => {
        if (!task.quantity) return '-';
        let unitLabel = task.quantityUnit || '';
        if (unitLabel === 'pcs') unitLabel = t('unit_pcs_short');
        if (unitLabel === 'boxes') unitLabel = t('unit_boxes_short');
        if (unitLabel === 'pallet') unitLabel = t('unit_pallet_short');
        return `${task.quantity} ${unitLabel}`;
    };

    const renderFormattedText = (text: string | undefined) => {
        if (!text) return '-';
        if (!text.includes(';')) return text;
        const parts = text.split(';');
        return parts.map((part, index) => (
            <React.Fragment key={index}>
                {part.trim()}
                {index < parts.length - 1 && (
                    <span className="mx-1.5 text-teal-500/40 font-light inline-block scale-90">→</span>
                )}
            </React.Fragment>
        ));
    };

    const handleExport = () => {
        if (typeof XLSX === 'undefined') {
            alert('Export library missing.');
            return;
        }
        const data = allLogisticsTasks.map(item => ({
            [t('miss_th_created')]: formatTime(item.createdAt),
            [t('miss_th_creator')]: resolveName(item.createdBy),
            [t('log_th_reference')]: item.partNumber || '-',
            [language === 'sk' ? 'ŠPZ' : 'PLATE']: item.note || '-',
            [t('log_th_operation')]: item.workplace || '-',
            [t('log_th_quantity')]: getQuantityString(item),
            [t('log_th_priority')]: item.priority || 'NORMAL',
            [t('log_th_status')]: item.isDone ? t('status_completed') : t('status_open'),
            [t('log_th_completed_by')]: resolveName(item.completedBy),
            [t('miss_th_when')]: formatTime(item.completedAt)
        }));

        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, t('log_sheet_name'));
        XLSX.writeFile(wb, `Logistics_Report_${dateFrom}_to_${dateTo}.xlsx`);
    };

    const handleDelete = (id: string) => {
        if (window.confirm(t('miss_delete_confirm'))) {
            onDeleteTask(id);
        }
    }

    const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-2xl p-4 shadow-xl backdrop-blur-sm transition-all";
    const inputClass = "bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white focus:border-sky-500 outline-none transition-all w-full text-center font-mono";

    return (
        <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in">

            {/* --- CONTROL PANEL (DATE/TIME FILTERS) --- */}
            <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl p-6 shadow-2xl overflow-hidden relative">
                {isLoading && (
                    <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm z-10 flex items-center justify-center">
                        <div className="flex items-center gap-3 px-6 py-3 bg-slate-800 border border-slate-700 rounded-2xl shadow-2xl">
                             <div className="w-5 h-5 border-2 border-sky-500 border-t-transparent rounded-full animate-spin"></div>
                             <span className="text-xs font-black text-white uppercase tracking-widest">{t('loading_archives')}</span>
                        </div>
                    </div>
                )}

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-end">
                    <div className="lg:col-span-3 space-y-3">
                        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-1">{t('filter_date_from')}</h4>
                        <div className="flex gap-2">
                            <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className={inputClass} />
                            <input type="time" value={timeFrom} onChange={e => setTimeFrom(e.target.value)} className={inputClass} />
