                                                    <span className="text-[11px] text-gray-300 font-bold truncate max-w-[100px] uppercase">{resolveName(item.completedBy || item.inProgressBy)}</span>
                                                </div>
                                            </td>
                                            <td className="py-4 px-6 text-right whitespace-nowrap">
                                                <p className="text-[10px] text-gray-500 font-mono">{formatTime(item.completedAt)}</p>
