                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={hasPermission('perm_btn_delete') ? 10 : 9} className="py-40 text-center text-gray-600 italic">
                                        <div className="flex flex-col items-center gap-4">
                                            <div className="p-6 bg-slate-900 rounded-full border border-slate-700 opacity-20">
                                                <TruckIcon className="h-12 w-12" />
                                            </div>
                                            <p className="font-black uppercase tracking-[0.3em] text-sm">{t('no_data')}</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

