const TruckIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 0m-4 0a2 2 0 114 0" />
    </svg>
);

const LogisticsCenterTab: React.FC<LogisticsCenterTabProps> = ({ tasks, draftTasks, fetchSanons, onDeleteTask, hasPermission, resolveName }) => {
    const { t, language } = useLanguage();

    // --- FILTRE ---
    const todayStr = new Date().toISOString().split('T')[0];
    const [dateFrom, setDateFrom] = useState(todayStr);
    const [dateTo, setDateTo] = useState(todayStr);
    const [timeFrom, setTimeFrom] = useState('00:00');
    const [timeTo, setTimeTo] = useState('23:59');

    const [filterQuery, setFilterQuery] = useState('');
    const [quickFilter, setQuickFilter] = useState<'ALL' | 'INBOUND' | 'OUTBOUND' | 'PENDING'>('ALL');

    // --- DATA STATE ---
    const [historicalData, setHistoricalData] = useState<Task[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    // Načítanie historických dát ak je zvolený starší dátum (sanony)
    useEffect(() => {
        const loadHistoryIfNeeded = async () => {
            if (dateFrom < todayStr || dateTo < todayStr) {
                setIsLoading(true);
                try {
                    const sanons = await fetchSanons();
                    const allArchived: Task[] = [];
                    sanons.forEach(s => {
                        if (s.tasks && Array.isArray(s.tasks)) {
                            allArchived.push(...s.tasks);
                        }
                    });
                    setHistoricalData(allArchived);
                } catch (e) {
                    console.error("Failed to load archive", e);
                } finally {
                    setIsLoading(false);
                }
            } else {
                setHistoricalData([]);
            }
        };
        loadHistoryIfNeeded();
    }, [dateFrom, dateTo, todayStr, fetchSanons]);

    // --- AGREGÁCIA A FILTRÁCIA ---
    const allLogisticsTasks = useMemo(() => {
        // Spojenie zdrojov: Live + Draft + History
        const combined = [...tasks, ...draftTasks, ...historicalData];

        // Unifikácia podľa ID (prevencia duplikátov pri fetchovaní)
        const uniqueMap = new Map();
        combined.forEach(t => {
            if (t.isLogistics) uniqueMap.set(t.id, t);
        });

        const startTs = new Date(`${dateFrom}T${timeFrom}`).getTime();
        const endTs = new Date(`${dateTo}T${timeTo}`).getTime();

        return Array.from(uniqueMap.values())
            .filter((task: Task) => {
                const taskTime = task.completedAt || task.createdAt || 0;
                // Filter Dátum a Čas
                if (taskTime < startTs || taskTime > endTs) return false;

                // Quick Filter (Smer jazdy / Stav)
                if (quickFilter === 'INBOUND') {
                    const op = (task.workplace || '').toUpperCase();
                    if (!(op.includes('VYKLÁDKA') || op.includes('UNLOADING') || op.includes('PRÍJEM'))) return false;
                } else if (quickFilter === 'OUTBOUND') {
                    const op = (task.workplace || '').toUpperCase();
                    if (!(op.includes('NAKLÁDKA') || op.includes('LOADING') || op.includes('EXPEDÍCIA'))) return false;
                } else if (quickFilter === 'PENDING') {
                    if (task.isDone) return false;
                }

                // Fulltext vyhľadávanie
                if (filterQuery) {
                    const q = filterQuery.toLowerCase();
                    const searchable = `${task.partNumber} ${task.workplace} ${task.note} ${resolveName(task.completedBy)}`.toLowerCase();
                    if (!searchable.includes(q)) return false;
                }

                return true;
            })
            .sort((a, b) => (b.completedAt || b.createdAt || 0) - (a.completedAt || a.createdAt || 0));
    }, [tasks, draftTasks, historicalData, dateFrom, dateTo, timeFrom, timeTo, quickFilter, filterQuery, resolveName]);

    const stats = useMemo(() => {
        let inbound = 0;
        let outbound = 0;
        let pending = 0;

        allLogisticsTasks.forEach(task => {
            const qty = parseFloat((task.quantity || '0').replace(',', '.'));
            const op = (task.workplace || '').toUpperCase();

            if (op.includes('VYKLÁDKA') || op.includes('UNLOADING') || op.includes('PRÍJEM')) {
                inbound += qty;
            } else if (op.includes('NAKLÁDKA') || op.includes('LOADING') || op.includes('EXPEDÍCIA')) {
                outbound += qty;
            }

            if (!task.isDone) {
                pending++;
            }
        });

        return { inbound, outbound, pending };
    }, [allLogisticsTasks]);

    const formatTime = (ts?: number) => {
        if (!ts) return '-';
        const date = new Date(ts);
        const now = new Date();
        const isToday = date.toDateString() === now.toDateString();

        const yesterday = new Date(now);
        yesterday.setDate(yesterday.getDate() - 1);
        const isYesterday = date.toDateString() === yesterday.toDateString();

        const timeStr = date.toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });

        if (isToday) return language === 'sk' ? `Dnes, ${timeStr}` : `Today, ${timeStr}`;
        if (isYesterday) return language === 'sk' ? `Včera, ${timeStr}` : `Yesterday, ${timeStr}`;
        return date.toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit' }) + ' ' + timeStr;
    };

    const getQuantityString = (task: Task) => {
        if (!task.quantity) return '-';
        let unitLabel = task.quantityUnit || '';
        if (unitLabel === 'pcs') unitLabel = t('unit_pcs_short');
        if (unitLabel === 'boxes') unitLabel = t('unit_boxes_short');
        if (unitLabel === 'pallet') unitLabel = t('unit_pallet_short');
        return `${task.quantity} ${unitLabel}`;
    };

    const renderFormattedText = (text: string | undefined) => {
        if (!text) return '-';
        if (!text.includes(';')) return text;
        const parts = text.split(';');
        return parts.map((part, index) => (
            <React.Fragment key={index}>
                {part.trim()}
                {index < parts.length - 1 && (
                    <span className="mx-1.5 text-teal-500/40 font-light inline-block scale-90">→</span>
                )}
            </React.Fragment>
        ));
    };

    const handleExport = () => {
        if (typeof XLSX === 'undefined') {
            alert('Export library missing.');
            return;
        }
        const data = allLogisticsTasks.map(item => ({
            [t('miss_th_created')]: formatTime(item.createdAt),
            [t('miss_th_creator')]: resolveName(item.createdBy),
            [t('log_th_reference')]: item.partNumber || '-',
            [language === 'sk' ? 'ŠPZ' : 'PLATE']: item.note || '-',
            [t('log_th_operation')]: item.workplace || '-',
            [t('log_th_quantity')]: getQuantityString(item),
            [t('log_th_priority')]: item.priority || 'NORMAL',
            [t('log_th_status')]: item.isDone ? t('status_completed') : t('status_open'),
            [t('log_th_completed_by')]: resolveName(item.completedBy),
            [t('miss_th_when')]: formatTime(item.completedAt)
        }));

        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, t('log_sheet_name'));
        XLSX.writeFile(wb, `Logistics_Report_${dateFrom}_to_${dateTo}.xlsx`);
    };

    const handleDelete = (id: string) => {
        if (window.confirm(t('miss_delete_confirm'))) {
            onDeleteTask(id);
        }
    }

    const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-2xl p-4 shadow-xl backdrop-blur-sm transition-all";
    const inputClass = "bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white focus:border-sky-500 outline-none transition-all w-full text-center font-mono";

    return (
        <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in">

            {/* --- CONTROL PANEL (DATE/TIME FILTERS) --- */}
            <div className="bg-slate-900 border-2 border-slate-800 rounded-3xl p-6 shadow-2xl overflow-hidden relative">
                {isLoading && (
                    <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm z-10 flex items-center justify-center">
                        <div className="flex items-center gap-3 px-6 py-3 bg-slate-800 border border-slate-700 rounded-2xl shadow-2xl">
                             <div className="w-5 h-5 border-2 border-sky-500 border-t-transparent rounded-full animate-spin"></div>
                             <span className="text-xs font-black text-white uppercase tracking-widest">{t('loading_archives')}</span>
                        </div>
                    </div>
                )}

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-end">
                    <div className="lg:col-span-3 space-y-3">
                        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-1">{t('filter_date_from')}</h4>
                        <div className="flex gap-2">
                            <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className={inputClass} />
                            <input type="time" value={timeFrom} onChange={e => setTimeFrom(e.target.value)} className={inputClass} />
                        </div>
                    </div>
                    <div className="lg:col-span-3 space-y-3">
                        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-1">{t('filter_date_to')}</h4>
                        <div className="flex gap-2">
                            <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className={inputClass} />
                            <input type="time" value={timeTo} onChange={e => setTimeTo(e.target.value)} className={inputClass} />
                        </div>
                    </div>
                    <div className="lg:col-span-4 space-y-3">
                        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-1">{t('task_search_placeholder')}</h4>
                        <div className="relative">
                            <input 
                                type="text" 
                                value={filterQuery}
                                onChange={(e) => setFilterQuery(e.target.value)}
                                placeholder="..."
                                className="w-full h-10 bg-slate-950 border border-slate-700 rounded-xl px-4 pl-10 text-sm text-white focus:outline-none focus:ring-2 focus:ring-sky-500 transition-all font-medium uppercase"
                            />
                            <svg xmlns="http://www.w3.org/2000/svg" className="absolute left-3 top-3 h-4 w-4 text-gray-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                            </svg>
                        </div>
                    </div>
                    <div className="lg:col-span-2">
                        <button 
                            onClick={handleExport}
                            className="w-full h-10 bg-green-700 hover:bg-green-600 text-white rounded-xl text-xs font-black shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 border-b-4 border-green-900"
                        >
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                            </svg>
                            {t('export_excel')}
                        </button>
                    </div>
                </div>
            </div>

            {/* --- KPI TILES --- */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div onClick={() => setQuickFilter('INBOUND')} className={`cursor-pointer ${cardClass} hover:scale-[1.02] ${quickFilter === 'INBOUND' ? 'border-green-500 ring-2 ring-green-500/20' : ''}`}>
                    <div className="flex justify-between items-start">
                        <div>
                            <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'PRÍJEM (Vykládka)' : 'INBOUND'}</p>
                            <p className="text-3xl font-black text-green-400 mt-1">{stats.inbound} <span className="text-xs font-normal text-gray-500">pal</span></p>
                        </div>
                        <div className="p-2 bg-green-500/10 rounded-lg text-green-500">
                            <ArrowDownIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>

                <div onClick={() => setQuickFilter('OUTBOUND')} className={`cursor-pointer ${cardClass} hover:scale-[1.02] ${quickFilter === 'OUTBOUND' ? 'border-sky-500 ring-2 ring-sky-500/20' : ''}`}>
                    <div className="flex justify-between items-start">
                        <div>
                            <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'EXPEDÍCIA (Nakládka)' : 'OUTBOUND'}</p>
                            <p className="text-3xl font-black text-sky-400 mt-1">{stats.outbound} <span className="text-xs font-normal text-gray-500">pal</span></p>
                        </div>
                        <div className="p-2 bg-sky-500/10 rounded-lg text-sky-500">
                            <ArrowUpIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>

                <div onClick={() => setQuickFilter('PENDING')} className={`cursor-pointer ${cardClass} hover:scale-[1.02] ${quickFilter === 'PENDING' ? 'border-orange-500 ring-2 ring-orange-500/20' : ''}`}>
                    <div className="flex justify-between items-start">
                        <div>
                            <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'V ČAKANÍ' : 'PENDING'}</p>
                            <p className="text-3xl font-black text-orange-400 mt-1">{stats.pending} <span className="text-xs font-normal text-gray-500">úloh</span></p>
                        </div>
                        <div className="p-2 bg-orange-500/10 rounded-lg text-orange-500">
                            <ClockIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>
            </div>

            {/* --- DATA TABLE --- */}
            <div className="bg-gray-800 rounded-3xl shadow-2xl border border-gray-700 overflow-hidden">
                <div className="p-4 bg-gray-900/40 border-b border-gray-700 flex justify-between items-center">
                    <div className="flex gap-2">
                        <button onClick={() => setQuickFilter('ALL')} className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${quickFilter === 'ALL' ? 'bg-slate-700 text-white' : 'text-slate-500 hover:text-slate-300'}`}>{t('filter_all')}</button>
                        <button onClick={() => setQuickFilter('PENDING')} className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${quickFilter === 'PENDING' ? 'bg-orange-600/20 text-orange-400 border border-orange-500/30' : 'text-slate-500 hover:text-slate-300'}`}>{t('status_open')}</button>
                    </div>
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{allLogisticsTasks.length} {t('records')}</span>
                </div>

                <div className="overflow-x-auto custom-scrollbar"> 
                    <table className="w-full text-left border-collapse min-w-[900px]">
                        <thead>
                            <tr className="bg-gray-900/50 text-gray-400 text-[10px] font-black uppercase tracking-widest border-b border-gray-700">
                                <th className="py-4 px-6">{t('miss_th_created')}</th>
                                <th className="py-4 px-6">{t('log_th_reference')}</th>
