const LogisticsCenterTab: React.FC<LogisticsCenterTabProps> = ({ tasks, onDeleteTask, hasPermission, resolveName }) => {
    const { t, language } = useLanguage();
    const [filterQuery, setFilterQuery] = useState('');

    const logisticsTasks = useMemo(() => {
        return tasks.filter(t => t.isLogistics && !t.isDone)
            .filter(t => {
                if (!filterQuery) return true;
                const q = filterQuery.toLowerCase();
                return (t.partNumber || '').toLowerCase().includes(q) || 
                       (t.workplace || '').toLowerCase().includes(q) ||
                       (t.note || '').toLowerCase().includes(q);
            })
            .sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
    }, [tasks, filterQuery]);

    const stats = useMemo(() => {
        let inbound = 0;
        let outbound = 0;
        logisticsTasks.forEach(t => {
            const qty = parseFloat((t.quantity || '0').replace(',', '.'));
            const op = (t.workplace || '').toUpperCase();
            if (op.includes('VYKL') || op.includes('UNLOAD') || op.includes('PRÍJEM')) inbound += qty;
            else if (op.includes('NAKL') || op.includes('LOAD') || op.includes('EXPED')) outbound += qty;
        });
        return { inbound, outbound };
    }, [logisticsTasks]);

    const formatTime = (ts?: number) => {
        if (!ts) return '-';
        return new Date(ts).toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });
    };

    const handleExport = () => {
        if (typeof XLSX === 'undefined') return;
        const data = logisticsTasks.map(item => ({
            [t('miss_th_created')]: new Date(item.createdAt || 0).toLocaleString('sk-SK'),
            [t('log_th_reference')]: item.partNumber || '-',
            [language === 'sk' ? 'ŠPZ' : 'PLATE']: item.note || '-',
            [t('log_th_operation')]: item.workplace || '-',
            [t('log_th_quantity')]: item.quantity + ' ' + item.quantityUnit,
            [t('log_th_priority')]: item.priority || 'NORMAL'
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Logistika");
        XLSX.writeFile(wb, `Logistika_Live_${new Date().toISOString().split('T')[0]}.xlsx`);
    };

    return (
        <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">

            <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl flex flex-col md:flex-row justify-between items-center gap-6">
                <div className="flex items-center gap-4 w-full md:w-auto">
                    <div className="relative w-full md:w-96">
                        <input 
                            type="text" 
                            value={filterQuery}
                            onChange={(e) => setFilterQuery(e.target.value)}
                            placeholder={t('task_search_placeholder')}
                            className="w-full h-12 bg-gray-800 border border-gray-700 rounded-xl px-4 pl-12 text-white focus:ring-2 focus:ring-sky-500 transition-all font-mono uppercase"
                        />
                        <svg className="absolute left-4 top-3.5 h-5 w-5 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                    </div>
                </div>
                <button onClick={handleExport} className="w-full md:w-auto h-12 bg-green-700 hover:bg-green-600 text-white px-8 rounded-xl font-bold uppercase text-xs tracking-widest transition-all border-b-4 border-green-900 shadow-lg flex items-center justify-center gap-2">
                    <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                    EXPORT LIVE
                </button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="bg-slate-900/60 border border-slate-800 p-6 rounded-2xl flex justify-between items-center">
                    <div>
                        <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">AKTÍVNY PRÍJEM</p>
                        <p className="text-3xl font-black text-green-400 mt-1">{stats.inbound} <span className="text-sm font-normal text-slate-600">pal</span></p>
                    </div>
                    <div className="p-3 bg-green-500/10 rounded-xl text-green-500"><ArrowDownIcon className="w-8 h-8" /></div>
                </div>
                <div className="bg-slate-900/60 border border-slate-800 p-6 rounded-2xl flex justify-between items-center">
                    <div>
